1	export const runScenario = (scenario: unknown): { results: unknown[] } => {
2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums: single main items (with fee, newcomer first insurance) ---
6	  // These exercise the simplest quote path. A newcomer (0 years) with one item:
7	  // base + 10% first insurance, +5 fee.
8	
9	  // --- Premium: empty / fee only ---
10	  it("empty item list → premium 5 G (only the processing fee)", () => {
11	    const result = runScenario({
12	      customer: { yearsWithMHPCO: 0 },
13	      steps: [{ op: "quote", items: [] }],
14	    });
15	    expect(result.results[0]).toEqual({ premium: 5 });
16	  });
17	
18	  // --- Base premiums of main items (isolated base premium via base-premium helper expectations) ---
19	  it.todo("sword base premium is 100 G");
20	  it.todo("amulet base premium is 60 G");
21	  it.todo("staff base premium is 80 G");
22	  it.todo("potion base premium is 40 G");
23	
24	  // --- Components base premiums ---
25	  it.todo("one rune base premium is 25 G");
26	  it.todo("2 runes → 50 G base premium");
27	  it.todo("3 runes → 60 G base premium (block applies)");
28	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
29	  it.todo("7 runes → 175 G base premium");
30	
31	  // --- "Alike" components ---
32	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
33	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
34	
35	  // --- Item-specific modifiers in isolation (cursed / high enchantment) ---
36	  it.todo("cursed item adds 50% surcharge on the affected item's base premium");
37	  it.todo("highly enchanted item (enchantment >= 5) adds 30% surcharge on affected item base premium");
38	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
39	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
40	  it.todo("sword with exactly enchantment 5 and cursed → both surcharges apply");
41	
42	  // --- Policy-wide modifiers ---
43	  it.todo("customer with exactly 2 years → 20% loyalty discount applies (policy-wide)");
44	  it.todo("customer with 1 year → no loyalty discount");
45	  it.todo("first insurance carries a 10% surcharge per item");
46	  it.todo("each contract after the first quote gets a 15% follow-up discount (policy-wide)");
47	
48	  // --- Modifier scope on multi-item policies ---
49	  it.todo("cursed sword (100) + plain amulet (60) → base 160, +50 curse (50% of cursed item) → 210 before fee/policy modifiers");
50	  it.todo("item-specific modifiers apply to affected item; policy-wide to policy base; fee last");
51	
52	  // --- Rounding ---
53	  it.todo("premium yielding 197.5 G → 198 G (rounded up, MHPCO's favor)");
54	
55	  // --- Integration examples (premium) ---
56	  it.todo("newcomer cursed sword (0 yrs, steel, ench 3) → premium 165 G");
57	  it.todo("long-standing customer's second contract (3 yrs, cursed sword steel ench 7) → premium 160 G");
58	
59	  // --- Claim: standard reimbursement ---
60	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
61	  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible, no special clause)");
62	
63	  // --- Claim: enchantment threshold ---
64	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible)");
65	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full reimburse then deductible)");
66	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
67	  it.todo("dragon-material sword, exactly ench 8, damage 1000 → payout 400 (high-enchantment clause then deductible)");
68	
69	  // --- Claim: deductible per damage event ---
70	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
71	
72	  // --- Claim: multiple items of same type ---
73	  it.todo("policy with two swords → insurance sum 2000, cap 4000");
74	  it.todo("two sword damage entries → each treated as separate damage with own deductible");
75	  it.todo("more damage entries of a type than policy covers → claim rejected (throws/non-zero)");
76	
77	  // --- Claim: cap and insurance sum ---
78	  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
79	  it.todo("cursed sword → cap 2000 based on unmodified insurance value (modifiers do not raise cap)");
80	  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 (block discount does not affect sum)");
81	  it.todo("sword (cap 2000), two successive 1500 claims → first payout 1400 (cap remaining 600)");
82	  it.todo("sword (cap 2000), second 1500 claim → payout 600 (reduced to remaining cap), remaining 0");
83	
84	  // --- Claim: error cases ---
85	  it.todo("claim references damage for item not in policy → rejected");
86	  it.todo("claim with damage amount -200 → rejected");
87	
88	  // --- Quote: error cases ---
89	  it.todo("quote includes unknown item type (broomstick) → rejected");
90	
91	  // --- Multi-step scenario / CLI shape ---
92	  it.todo("scenario with a quote then a claim returns results array of matching length and order");
93	});
